Voici un exemple complet de contrôleur respectant les contraintes :

```csharp
[ApiController]
[Route("api/[controller]")]
[Authorize]
public class ProductsController : ControllerBase
{
    private readonly IProductService _productService;

    public ProductsController(IProductService productService)
    {
        _productService = productService;
    }

    [HttpGet]
    [Authorize(Roles = "User,Admin")]
    public async Task<ActionResult<IEnumerable<ProductDto>>> GetProducts()
    {
        var products = await _productService.GetAllAsync();
        return Ok(products);
    }

    [HttpPost]
    [Authorize(Roles = "Admin")]
    public async Task<ActionResult<ProductDto>> CreateProduct(ProductCreateDto productDto)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var created = await _productService.CreateAsync(productDto);
        return CreatedAtAction(nameof(GetProducts), new { id = created.Id }, created);
    }

    [HttpDelete("{id}")]
    [Authorize(Roles = "Admin")]
    public async Task<IActionResult> DeleteProduct(int id)
    {
        var success = await _productService.DeleteAsync(id);
        if (!success)
            return NotFound();
        return NoContent();
    }
}
```

Explications :
- `[Authorize]` sur le contrôleur impose une authentification globale.
- `[Authorize(Roles = "...")]` sur chaque action affine les droits.
- `CreatedAtAction` retourne 201 avec l’emplacement de la ressource.
- `NoContent()` est standard pour un DELETE réussi (204).
- Les DTOs (`ProductDto`, `ProductCreateDto`) évitent l’exposition directe des entités.

```csharp
[HttpPatch("{id}/status")]
[Authorize(Roles = "Manager")] // Au moins Manager peut toujours passer
public async Task<IActionResult> UpdateOrderStatus(int id, [FromBody] StatusUpdateDto dto)
{
    var order = await _context.Orders.FindAsync(id);
    if (order == null)
        return NotFound();

    // Récupération du userId depuis le token JWT
    var userIdClaim = User.FindFirst("userId")?.Value;
    if (userIdClaim == null)
        return Forbid();

    bool isOwner = order.UserId.ToString() == userIdClaim;
    bool isManager = User.IsInRole("Manager");

    if (!isManager && !isOwner)
        return Forbid();

    order.Status = dto.NewStatus;
    await _context.SaveChangesAsync();
    return NoContent();
}
```

Explication :
- `[Authorize(Roles = "Manager")]` seul ne suffit pas, car un Owner peut ne pas être Manager.
- On récupère le `userId` du token (ajouté lors de la création du JWT).
- On compare avec l’`order.UserId`.
- Si aucun des deux droits n’est satisfait → 403 Forbidden.
- La réponse 204 NoContent est standard pour un PATCH réussi.

```csharp
[ApiController]
[Route("api/[controller]")]
[Authorize]
public class TasksController : ControllerBase
{
    private readonly ITaskService _taskService;
    private readonly IHttpContextAccessor _httpContextAccessor;

    public TasksController(ITaskService taskService, IHttpContextAccessor httpContextAccessor)
    {
        _taskService = taskService;
        _httpContextAccessor = httpContextAccessor;
    }

    private int GetCurrentUserId()
    {
        var userIdClaim = User.FindFirst("userId")?.Value;
        return int.Parse(userIdClaim);
    }

    [HttpGet]
    public async Task<ActionResult<IEnumerable<TaskDto>>> GetTasks()
    {
        var userId = GetCurrentUserId();
        var isAdmin = User.IsInRole("Admin");
        var tasks = await _taskService.GetTasksAsync(userId, isAdmin);
        return Ok(tasks);
    }

    [HttpPost]
    public async Task<ActionResult<TaskDto>> CreateTask(TaskCreateDto dto)
    {
        var userId = GetCurrentUserId();
        var created = await _taskService.CreateAsync(dto, userId);
        return CreatedAtAction(nameof(GetTasks), new { id = created.Id }, created);
    }

    [HttpPut("{id}")]
    public async Task<IActionResult> UpdateTask(int id, TaskUpdateDto dto)
    {
        var userId = GetCurrentUserId();
        var isAdmin = User.IsInRole("Admin");
        var success = await _taskService.UpdateAsync(id, dto, userId, isAdmin);
        if (!success) return NotFound();
        return NoContent();
    }

    [HttpDelete("{id}")]
    public async Task<IActionResult> DeleteTask(int id)
    {
        var userId = GetCurrentUserId();
        var isAdmin = User.IsInRole("Admin");
        var success = await _taskService.DeleteAsync(id, userId, isAdmin);
        if (!success) return NotFound();
        return NoContent();
    }
}
```

Le service vérifie si l’utilisateur est autorisé (estAdmin ou propriétaire) avant chaque opération de modification/suppression.
